#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N,A,B,C; scanf("%d %d %d %d", &N, &A, &B, &C);
        int maxDishes = B < (A + C) ? B : (A + C);
        if(N <= maxDishes) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

